import React, { useEffect, useState } from "react";
import Dashboard from "./Dashboard";
import AddTask from "./AddTask";

export default function TaskList() {
  const [tasks, setTasks] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [deleteId, setDeleteId] = useState(null);

  const fetchAll = async () => {
    try {
      const t = await fetch("http://localhost:8086/tasks").then(r => r.json());
      const n = await fetch("http://localhost:8086/tasks/notifications").then(r => r.json());
      setTasks(t);
      setNotifications(n);
    } catch (err) {
      console.error("Error fetching data:", err);
    }
  };

  useEffect(() => { fetchAll(); }, []);

  // ✅ COMPLETE TASK (instant update)
  const completeTask = async (id) => {
    await fetch(`http://localhost:8086/tasks/${id}/complete`, { method: "PUT" });

    setTasks(prev =>
      prev.map(t => (t.id === id ? { ...t, completed: true } : t))
    );
  };

  // ✅ DELETE TASK (modal confirm)
  const deleteTask = async () => {
    if (!deleteId) return;

    await fetch(`http://localhost:8086/tasks/${deleteId}`, {
      method: "DELETE",
    });

    setTasks(prev => prev.filter(t => t.id !== deleteId));
    setDeleteId(null);
  };

  return (
    <div className="bg-gradient-to-br from-indigo-100 to-purple-200 min-h-screen p-6 font-sans">

      <Dashboard />

      {/* Add Task Button */}
      <div className="flex justify-end mb-6">
        <button
          onClick={() => setShowAddModal(true)}
          className="bg-gradient-to-r from-purple-500 to-indigo-500 text-white px-6 py-3 rounded-2xl shadow-lg hover:scale-105 transition-all duration-300"
        >
          + Add Task
        </button>
      </div>

      {/* ADD MODAL */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex justify-center items-center z-50">
          <AddTask
            closeModal={() => setShowAddModal(false)}
            onTaskAdded={(newTask) => {
              setTasks(prev => [...prev, newTask]); // ⚡ instant update
              setShowAddModal(false);
            }}
          />
        </div>
      )}

      {/* DELETE MODAL 🔥 */}
      {deleteId && (
        <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex justify-center items-center z-50">
          <div className="bg-white/20 backdrop-blur-xl border border-white/30 p-6 rounded-2xl shadow-2xl w-[350px] text-center">

            <h2 className="text-xl font-semibold text-white mb-3">
              Delete Task?
            </h2>

            <p className="text-gray-200 mb-6">
              This action cannot be undone.
            </p>

            <div className="flex justify-center gap-4">
              <button
                onClick={() => setDeleteId(null)}
                className="px-4 py-2 rounded-lg bg-white/30 hover:bg-white/40 text-black"
              >
                Cancel
              </button>

              <button
                onClick={deleteTask}
                className="px-4 py-2 rounded-lg bg-red-500 hover:bg-red-600 text-white"
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      )}

      {/* TASKS */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {tasks.map(t => (
          <div
            key={t.id}
            className={`p-6 rounded-2xl shadow-xl transition-all duration-300 hover:scale-[1.03] ${
              t.completed ? "bg-gray-200/70" : "bg-white/70 backdrop-blur-md"
            }`}
          >
            <div className="flex justify-between items-start">
              <div>
                <h3 className="text-lg font-semibold text-gray-800">{t.title}</h3>
                <p className="text-xs text-gray-500 mt-1">
                  {t.priority} • {t.dueDate}
                </p>
              </div>

              <div className="flex items-center gap-2">
                {!t.completed && (
                  <button
                    onClick={() => completeTask(t.id)}
                    className="text-green-600 hover:bg-green-100 px-3 py-1.5 rounded-md text-sm transition"
                  >
                    ✓
                  </button>
                )}

                <button
                  onClick={() => setDeleteId(t.id)}
                  className="text-red-500 hover:bg-red-100 px-3 py-1.5 rounded-md text-sm transition"
                >
                  ✕
                </button>
              </div>
            </div>

            {t.completed && (
              <div className="mt-4 text-green-700 font-semibold">
                Completed ✅
              </div>
            )}
          </div>
        ))}
      </div>

      {/* NOTIFICATIONS */}
      {notifications.length > 0 && (
        <div className="mt-10">
          <h2 className="text-2xl font-bold text-gray-700 mb-4">Notifications</h2>
          <ul className="space-y-2">
            {notifications.map(n => (
              <li key={n.id} className="p-4 bg-white/70 backdrop-blur-md rounded-xl shadow hover:shadow-lg transition">
                {n.message}
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}
